</body></html>`;

    return { subject, body: bodyText, htmlContent };
  }

  function togglePreview() {
    const box = document.getElementById('preview-box');
    box.classList.toggle('visible');
    if (box.classList.contains('visible')) {
      const sample = {
        name: 'Babatunde Adeyemi',
        position: 'President',
        datetime: '2026-07-10T10:00',
        venue: 'Architecture Studio Room 3',
      };
      const { subject, body } = buildEmail(sample);
      box.textContent = `Subject: ${subject}\n\n${body}`;
    }
  }

  /* ── SEND ── */

  function isValidEmail(email) {
    if (!email) return false;
    // Simple, practical email validation
    const re = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return re.test(email);
  }

  async function sendAll() {
    const apiKey = document.getElementById('api-key').value.trim();
    if (!apiKey) { showToast('Enter your Brevo API key first.', 'error'); return; }
    if (rows.length === 0) { showToast('No aspirants to send to.', 'warn'); return; }

    sending = true;
    document.getElementById('send-btn').disabled = true;
    document.getElementById('send-btn').textContent = '⏳ Sending…';

    const log = document.getElementById('log');
    log.innerHTML = '';
    log.classList.add('visible');
    const progWrap = document.getElementById('prog-wrap');
    const progFill = document.getElementById('prog-fill');
    progWrap.classList.add('visible');

    let sent = 0, failed = 0;

    for (let i = 0; i < rows.length; i++) {
      const r = rows[i];
      setStatus(r.id, 'sending');
      logLine(`[${i+1}/${rows.length}] Sending to ${r.name || '(no name)'} (${r.email || '(no email)'})…`, 'inf');

      const email = (r.email || '').trim();
      const name = (r.name || '').trim();

      if (!email || !name) {
        logLine(`  ✗ Skipped — missing name or email`, 'err');
        setStatus(r.id, 'error');
        failed++;
        continue;
      }

      if (!isValidEmail(email)) {
        logLine(`  ✗ Skipped — invalid email format: ${email}`, 'err');
        setStatus(r.id, 'error');
        failed++;
        continue;
      }

      const { subject, body, htmlContent } = buildEmail(r);

      try {
        const res = await fetch('https://api.brevo.com/v3/smtp/email', {
          method: 'POST',
          headers: {
            'api-key': apiKey,
            'Content-Type': 'application/json',
          },
          body: JSON.stringify({
            sender: {
              name:  document.getElementById('sender-name').value.trim(),
              email: document.getElementById('sender-email').value.trim(),
            },
            to: [{ email: email, name: name }],
            subject,
            htmlContent,
            textContent: body,
          }),
        });

        if (res.ok) {
          logLine(`  ✓ Sent to ${email}`, 'ok');
          setStatus(r.id, 'sent');
          sent++;
        } else {
          const err = await res.json().catch(() => ({}));
          // Show more detail when Brevo returns problem with "to" field
          const message = err.message || err?.errors?.[0]?.message || res.status;
          logLine(`  ✗ Failed: ${message}`, 'err');
          setStatus(r.id, 'error');
          failed++;
        }
      } catch(e) {
        logLine(`  ✗ Error: ${e.message}`, 'err');
        setStatus(r.id, 'error');
        failed++;
      }

      progFill.style.width = `${Math.round(((i+1)/rows.length)*100)}%`;
      await sleep(300); // gentle rate-limit buffer
    }

    logLine(`\nDone. ✓ ${sent} sent, ✗ ${failed} failed.`, sent === rows.length ? 'ok' : 'err');
    showToast(`Done — ${sent} sent, ${failed} failed.`, failed === 0 ? 'success' : 'warn');

    sending = false;
    document.getElementById('send-btn').disabled = false;
    document.getElementById('send-btn').innerHTML = '✉ Send Schedule Emails';
  }

  function setStatus(id, state) {
    const dot = document.getElementById('st-' + id);
    if (!dot) return;
    dot.className = 'row-status ' + (state === 'sending' ? 'sending' : state === 'sent' ? 'sent' : state === 'error' ? 'error' : '');
  }

  function logLine(msg, cls='inf') {
    const log = document.getElementById('log');
    const div = document.createElement('div');
    div.className = 'log-line ' + cls;
    div.textContent = msg;
    log.appendChild(div);
    log.scrollTop = log.scrollHeight;
  }

  function sleep(ms) { return new Promise(r => setTimeout(r, ms)); }

  /* ── TOAST ── */
  let toastTimer;
  function showToast(msg, type = 'success') {
    const t = document.getElementById('toast');
    t.textContent = msg;
    t.className = 'show ' + type;
    clearTimeout(toastTimer);
    toastTimer = setTimeout(() => { t.className = type; }, 3500);
  }
</script>
</body>
</html>
```

Notes and verification tips:
- The CSV parser now supports quoted fields and escaped double-quotes. If your CSV uses semicolons or a different delimiter, let me know and I can adapt it.
- Email validation uses a practical regex and will skip any rows with invalid addresses (they'll be marked with the red status dot and a log entry).
- The DOM building approach for rows prevents truncation or layout issues caused by innerHTML attribute interpolation.
- I preserved all features: CSV import/export, adding/removing rows, preview, Brevo sending, logs, progress, and toasts.

