  /* ── ROW MANAGEMENT ── */
  function addRow(data = {}) {
    // Generate a stable unique integer id
    const id = Date.now() + Math.floor(Math.random() * 1000000);
    const newRow = {
      id,
      name: data.name || '',
      email: data.email || '',
      position: data.position || '',
      datetime: data.datetime || '',
      venue: data.venue || ''
