  /* ── CSV ── */
  function importCSV(input) {
    try {
      const file = input.files ? input.files[0] : (input instanceof HTMLInputElement ? input.files[0] : null);
      if (!file) {
        console.error('importCSV: no file selected');
        return;
      }
      const reader = new FileReader();
      reader.onload = e => {
        try {
          const raw = String(e.target.result || '');
          // Normalize newlines
          const text = raw.replace(/\r\n/g, '\n').replace(/\r/g, '\n');
          const lines = text.split('\n').filter(l => l.trim().length > 0);
          let skipped = 0;
          // Skip header if it looks like headers
          const startIndex = (lines.length > 0 && /name|email/i.test(lines[0])) ? 1 : 0;
          console.log(`Importing CSV lines=${lines.length}, startIndex=${startIndex}`);
          for (let i = startIndex; i < lines.length; i++) {
            const line = lines[i];
            const cols = parseCSVLine(line);
            // Accept rows with at least name & email
            if (!cols || cols.length < 2) { skipped++; console.warn('CSV row skipped (less than 2 columns):', line); continue; }
            addRow({
              name:     (cols[0] || '').trim(),
              email:    (cols[1] || '').trim(),
              position: (cols[2] || '').trim(),
              datetime: (cols[3] || '').trim(),
              venue:    (cols[4] || '').trim(),
            });
          }
          showToast(`Imported ${rows.length} aspirant(s)${skipped ? ` (${skipped} rows skipped)` : ''}`, 'success');
          console.log('CSV import complete', { total: rows.length, skipped });
        } catch (err) {
          console.error('Error processing CSV in reader.onload:', err);
          showToast('Failed to import CSV', 'error');
        }
      };
      reader.onerror = (err) => {
        console.error('FileReader error', err);
        showToast('Failed to read CSV file', 'error');
      };
      reader.readAsText(file, 'UTF-8');
      // reset input so same file can be imported again
      if (input && input.files) input.value = '';
    } catch (err) {
      console.error('importCSV error', err);
      showToast('Failed to import CSV', 'error');
    }
  }

  function parseCSVLine(line) {
    // Robust CSV line parser per RFC4180-ish small subset:
    // - Supports quoted fields with commas inside
    // - Supports escaped quotes as double quotes ("")
    const result = [];
    let cur = '';
    let inQuotes = false;
    for (let i = 0; i < line.length; i++) {
      const ch = line[i];
      if (ch === '"') {
        // If next char is also quote, it's an escaped quote
        if (inQuotes && line[i+1] === '"') {
          cur += '"';
          i++; // skip escaped quote
          continue;
        }
        inQuotes = !inQuotes;
        continue;
      }
      if (ch === ',' && !inQuotes) {
        result.push(cur);
        cur = '';
        continue;
      }
      cur += ch;
    }
    result.push(cur);
    // Trim surrounding whitespace from each cell, but preserve inner spaces
    return result.map(s => s.replace(/\r$/, '').trim());
  }

