  /* ── SEND ── */

  function isValidEmail(email) {
    if (!email) return false;
    // Simple but practical validation (rejects obviously invalid emails)
    const re = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return re.test(String(email).trim());
  }

  async function sendAll() {
    const apiKey = document.getElementById('api-key').value.trim();
    if (!apiKey) { showToast('Enter your Brevo API key first.', 'error'); console.error('sendAll: missing API key'); return; }
    if (rows.length === 0) { showToast('No aspirants to send to.', 'warn'); console.warn('sendAll: no rows'); return; }

    sending = true;
    const sendBtn = document.getElementById('send-btn');
    if (sendBtn) {
      sendBtn.disabled = true;
      sendBtn.textContent = '⏳ Sending…';
    }

    const log = document.getElementById('log');
