    const progWrap = document.getElementById('prog-wrap');
    const progFill = document.getElementById('prog-fill');
    if (progWrap) progWrap.classList.add('visible');

    let sent = 0, failed = 0;

    console.log('Starting sendAll for', rows.length, 'rows');

