     /* ── ROW MANAGEMENT ── */
     function addRow(data = {}) {
       // Generate a stable unique integer id
       const id = Date.now() + Math.floor(Math.random() * 1000000);
       const newRow = {
         id,
         name: data.name || '',
         email: data.email || '',
         position: data.position || '',
         datetime: data.datetime || '',
         venue: data.venue || ''
       };
       rows.push(newRow);
       console.log('Row added', newRow);
       renderRows();
     }

     function removeRow(id) {
       const i = rows.findIndex(r => r.id === id);
       if (i > -1) {
         console.log('Removing row id=', id);
         rows.splice(i, 1);
         renderRows();
       } else {
         console.error('Attempted to remove non-existent row id=', id);
       }
     }

     function updateRow(id, field, value) {
       const r = rows.find(rr => rr.id === id);
       if (r) {
         if (field === 'email') value = String(value || '').trim();
         r[field] = value;
         // Debug log on updates (silence noisy logs if needed)
         // console.log(`Updated row ${id} ${field}=${value}`);
       } else {
         console.error('updateRow: row not found id=', id);
