    border-radius: var(--radius);
    font-family: var(--sans);
    font-size: 13px;
    font-weight: 600;
    cursor: pointer;
    display: flex;
    align-items: center;
    gap: 6px;
    transition: opacity .15s;
  }
  .btn-add:hover { opacity: .85; }

  .aspirants-table {
    background: #fff;
    border: 1px solid var(--border);
    border-radius: var(--radius);
    overflow: hidden;
    margin-bottom: 28px;
  }
  .tbl-head {
    display: grid;
    grid-template-columns: 2fr 2fr 1.5fr 1.4fr 1.4fr 44px;
    background: #122f1c;
    color: rgba(255,255,255,0.8);
    font-size: 11px;
    font-weight: 600;
    letter-spacing: 0.1em;
    text-transform: uppercase;
    padding: 10px 14px;
    gap: 10px;
  }
  .aspirant-row {
    display: grid;
    grid-template-columns: 2fr 2fr 1.5fr 1.4fr 1.4fr 44px;
    gap: 10px;
    padding: 10px 14px;
    border-top: 1px solid var(--border);
    align-items: center;
  }
  .aspirant-row:nth-child(even) { background: #FAFAF8; }
  .aspirant-row input {
    font-size: 13px;
    padding: 7px 9px;
    background: transparent;
    border-color: transparent;
    width: 100%;
  }
  .aspirant-row input:focus { background: #fff; border-color: var(--accent); }
  .aspirant-row input[type="datetime-local"] { font-family: var(--mono); font-size: 12px; }

  .row-status {
    width: 10px;
    height: 10px;
    border-radius: 50%;
    background: var(--border);
    display: inline-block;
    margin-right: 6px;
    flex-shrink: 0;
  }
  .row-status.sent { background: #22C55E; }
  .row-status.error { background: #EF4444; }
  .row-status.sending { background: var(--gold); }

  .btn-del {
    background: none;
    border: none;
    cursor: pointer;
    color: #CBD5E1;
    font-size: 18px;
    line-height: 1;
    padding: 2px;
    transition: color .15s;
  }
  .btn-del:hover { color: var(--error); }

  .empty-state {
    text-align: center;
    padding: 40px 20px;
    color: var(--muted);
    font-size: 14px;
  }

  /* ── IMPORT ── */
  .import-strip {
    background: #fff;
    border: 1px solid var(--border);
    border-radius: var(--radius);
    padding: 16px 20px;
    margin-bottom: 20px;
    display: flex;
    align-items: center;
    gap: 14px;
    flex-wrap: wrap;
  }
  .import-strip span { font-size: 13px; color: var(--muted); }
  .btn-ghost {
    background: none;
    border: 1.5px solid var(--border);
    color: var(--ink);
    padding: 7px 14px;
    border-radius: var(--radius);
    font-family: var(--sans);
    font-size: 13px;
    font-weight: 500;
    cursor: pointer;
    transition: border-color .15s;
  }
  .btn-ghost:hover { border-color: var(--accent); color: var(--accent); }
  #csv-input { display: none; }

  /* ── SEND BAR ── */
  .send-bar {
    position: fixed;
    bottom: 0; left: 0; right: 0;
    background: var(--ink);
    border-top: 3px solid var(--gold);
    padding: 14px 32px;
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 16px;
    z-index: 100;
  }
  .send-bar .count { color: rgba(255,255,255,0.6); font-size: 13px; }
  .send-bar .count strong { color: #fff; }

  .btn-send {
    background: var(--gold);
    color: var(--ink);
    border: none;
    padding: 11px 28px;
    border-radius: var(--radius);
    font-family: var(--sans);
    font-size: 14px;
    font-weight: 700;
    cursor: pointer;
    transition: opacity .15s;
    display: flex;
    align-items: center;
    gap: 8px;
  }
  .btn-send:hover:not(:disabled) { opacity: .85; }
  .btn-send:disabled { opacity: .5; cursor: not-allowed; }

  /* ── LOG ── */
  .log {
    background: var(--ink);
    border-radius: var(--radius);
    padding: 16px;
    font-family: var(--mono);
    font-size: 12px;
    max-height: 200px;
    overflow-y: auto;
    margin-bottom: 80px;
    display: none;
  }
  .log.visible { display: block; }
  .log-line { padding: 2px 0; }
  .log-line.ok  { color: #4ADE80; }
  .log-line.err { color: #F87171; }
  .log-line.inf { color: #93C5FD; }

  /* ── TOAST ── */
  #toast {
    position: fixed;
    top: 20px; right: 20px;
    padding: 12px 18px;
    border-radius: var(--radius);
    font-size: 13px;
    font-weight: 600;
    z-index: 999;
    opacity: 0;
    transform: translateY(-8px);
    transition: opacity .25s, transform .25s;
    pointer-events: none;
    max-width: 320px;
  }
  #toast.show { opacity: 1; transform: translateY(0); }
  #toast.success { background: var(--success-bg); color: var(--success); border: 1px solid #BBF7D0; }
  #toast.error   { background: var(--error-bg);   color: var(--error);   border: 1px solid #FECACA; }
  #toast.warn    { background: var(--warn-bg);     color: var(--warn);    border: 1px solid #FDE68A; }

  /* ── PROGRESS ── */
  .progress-bar-wrap {
    height: 3px;
    background: rgba(255,255,255,.15);
    border-radius: 2px;
    flex: 1;
    display: none;
  }
  .progress-bar-wrap.visible { display: block; }
  .progress-bar-fill {
    height: 100%;
    background: var(--gold);
    border-radius: 2px;
    transition: width .3s;
    width: 0%;
  }
</style>
</head>
<body>

<header>
  <div class="eyebrow">Themis Vanguard · LASUASA IEC</div>
