<!-- SEND BAR -->
<div class="send-bar">
  <div class="count"><strong id="bar-count">0</strong> aspirant(s) loaded</div>
  <div class="progress-bar-wrap" id="prog-wrap">
    <div class="progress-bar-fill" id="prog-fill"></div>
  </div>
  <button class="btn-send" id="send-btn" onclick="sendAll()" disabled>
    ✉ Send Schedule Emails
  </button>
</div>

<div id="toast"></div>

<script>
/*
  Changes summary in this script:
  - Added scheduling controls and generateSchedule() to auto-assign datetime slots.
  - CSV import now recognizes FirstName/MiddleName/LastName/Name columns and maps appropriately.
  - Removed email preview UI/behavior.
  - Email template now supports placeholders: {{first_name}}, {{middle_name}}, {{last_name}}, {{name}}.
  - "Auto assign on import" option applies the scheduling automatically on CSV import.
  - Kept all previous features and added console logs & defensive checks.
*/

const rows = []; // each row: { id, first_name, middle_name, last_name, name, email, position, datetime, venue, [other cols...] }
let sending = false;

(function attachListeners() {
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', init);
  } else {
    init();
  }

  function init() {
    const addBtn = document.getElementById('add-btn');
    const importBtn = document.getElementById('import-btn');
    const csvInput = document.getElementById('csv-input');
    const downloadBtn = document.getElementById('download-template-btn');
    const genBtn = document.getElementById('generate-schedule-btn');

    if (addBtn) addBtn.addEventListener('click', () => { console.log('Add Aspirant'); addRow(); });
    else console.error('Add button not found');

    if (importBtn && csvInput) {
      importBtn.addEventListener('click', () => csvInput.click());
      csvInput.addEventListener('change', (e) => importCSV(e.target));
    } else console.error('Import controls missing');

    if (downloadBtn) downloadBtn.addEventListener('click', downloadTemplate);
    if (genBtn) genBtn.addEventListener('click', () => { console.log('Manual schedule generation requested'); generateSchedule(); });

    updateBarCount();
    console.log('Init complete');
  }
})();

/* ROW MANAGEMENT */
function addRow(data = {}) {
  const id = Date.now() + Math.floor(Math.random() * 1000000);
  const r = {
    id,
    first_name: data.first_name || '',
    middle_name: data.middle_name || '',
    last_name: data.last_name || '',
    name: data.name || ((data.first_name || '') + (data.middle_name ? ' ' + data.middle_name : '') + (data.last_name ? ' ' + data.last_name : '')).trim(),
    email: data.email || '',
    position: data.position || '',
    datetime: data.datetime || '',
    venue: data.venue || '',
    // keep raw extra columns if needed
    _raw: data._raw || {}
  };
  rows.push(r);
  console.log('Added row', r);
  renderRows();
}

function removeRow(id) {
  const i = rows.findIndex(r => r.id === id);
  if (i > -1) {
    rows.splice(i, 1);
    console.log('Removed row', id);
    renderRows();
  } else console.error('removeRow: id not found', id);
}

function updateRow(id, field, value) {
  const r = rows.find(x => x.id === id);
  if (!r) { console.error('updateRow: row not found', id); return; }
  if (field === 'name') {
    // update name and keep split parts in sync loosely: do not overwrite explicit first/last if present
    r.name = String(value || '').trim();
    // attempt to split into parts if first/last empty
    if (!r.first_name && !r.last_name) {
      const parts = r.name.split(/\s+/).filter(Boolean);
      if (parts.length === 1) { r.first_name = parts[0]; }
      else if (parts.length === 2) { r.first_name = parts[0]; r.last_name = parts[1]; }
      else if (parts.length > 2) { r.first_name = parts[0]; r.last_name = parts[parts.length-1]; r.middle_name = parts.slice(1, -1).join(' '); }
    }
  } else {
    r[field] = value;
    if ((field === 'first_name' || field === 'middle_name' || field === 'last_name')) {
      r.name = ((r.first_name || '') + (r.middle_name ? ' ' + r.middle_name : '') + (r.last_name ? ' ' + r.last_name : '')).trim();
    }
  }
  updateBarCount();
}

/* RENDER ROWS */
function renderRows() {
  const container = document.getElementById('rows-container');
  const empty = document.getElementById('empty-msg');
  if (!container) { console.error('rows-container missing'); return; }

  if (rows.length === 0) {
    container.innerHTML = '';
    if (empty) container.appendChild(empty);
    if (empty) empty.style.display = '';
    updateBarCount();
    return;
  }

  if (empty) empty.style.display = 'none';
  container.innerHTML = '';

  rows.forEach(r => {
    const row = document.createElement('div');
    row.className = 'aspirant-row';
    row.id = 'row-' + r.id;

    // Name + status dot
    const colName = document.createElement('div');
    colName.style.display = 'flex';
    colName.style.alignItems = 'center';
    colName.style.gap = '6px';

    const status = document.createElement('span');
    status.className = 'row-status';
    status.id = 'st-' + r.id;

    const nameInput = document.createElement('input');
    nameInput.type = 'text';
    nameInput.placeholder = 'Full name';
    nameInput.value = r.name || '';
    nameInput.addEventListener('input', (e) => updateRow(r.id, 'name', e.target.value));

    colName.appendChild(status);
    colName.appendChild(nameInput);
    row.appendChild(colName);

    // Email
    const colEmail = document.createElement('div');
    const emailInput = document.createElement('input');
    emailInput.type = 'email';
    emailInput.placeholder = 'email@…';
    emailInput.value = r.email || '';
    emailInput.addEventListener('input', (e) => updateRow(r.id, 'email', e.target.value));
    colEmail.appendChild(emailInput);
    row.appendChild(colEmail);

    // Position
    const colPos = document.createElement('div');
    const posInput = document.createElement('input');
    posInput.type = 'text';
    posInput.placeholder = 'Position';
    posInput.value = r.position || '';
    posInput.addEventListener('input', (e) => updateRow(r.id, 'position', e.target.value));
    colPos.appendChild(posInput);
    row.appendChild(colPos);

    // DateTime
    const colDt = document.createElement('div');
    const dtInput = document.createElement('input');
    dtInput.type = 'datetime-local';
    dtInput.value = r.datetime || '';
    dtInput.addEventListener('input', (e) => updateRow(r.id, 'datetime', e.target.value));
    colDt.appendChild(dtInput);
    row.appendChild(colDt);

    // Venue
    const colVenue = document.createElement('div');
    const venueInput = document.createElement('input');
    venueInput.type = 'text';
    venueInput.placeholder = '(use default)';
    venueInput.value = r.venue || '';
    venueInput.addEventListener('input', (e) => updateRow(r.id, 'venue', e.target.value));
    colVenue.appendChild(venueInput);
    row.appendChild(colVenue);

    // Action
    const colAction = document.createElement('div');
    colAction.style.textAlign = 'right';
    const delBtn = document.createElement('button');
    delBtn.className = 'btn-del';
    delBtn.title = 'Remove';
    delBtn.innerHTML = '×';
    delBtn.addEventListener('click', () => removeRow(r.id));
    colAction.appendChild(delBtn);
    row.appendChild(colAction);

    container.appendChild(row);
  });

  updateBarCount();
}

/* UTILS */
function updateBarCount() {
  const count = rows.length;
  const bar = document.getElementById('bar-count');
  const h2 = document.querySelector('.table-header h2');
  const sendBtn = document.getElementById('send-btn');
  if (bar) bar.textContent = count;
  if (h2) h2.textContent = `Aspirants (${count})`;
  if (sendBtn) sendBtn.disabled = count === 0 || sending;
}

function sleep(ms) { return new Promise(resolve => setTimeout(resolve, ms)); }

/* CSV PARSING & IMPORT */
function parseCSVLine(line) {
  // robust CSV parsing: handles quoted fields and escaped quotes
  const out = [];
  let cur = '';
  let inQuotes = false;
  for (let i = 0; i < line.length; i++) {
    const ch = line[i];
    if (ch === '"') {
      if (inQuotes && line[i+1] === '"') {
        cur += '"';
        i++;
        continue;
      }
      inQuotes = !inQuotes;
      continue;
    }
    if (ch === ',' && !inQuotes) {
      out.push(cur);
      cur = '';
      continue;
    }
    cur += ch;
  }
  out.push(cur);
  return out.map(s => s.replace(/\r$/, '').trim());
}

function normalizeHeaderName(h) {
  return String(h || '').trim().toLowerCase().replace(/[^a-z0-9]+/g, '_');
}

function mapHeaderIndices(headerCols) {
  // returns an object mapping canonical names to indices
  const map = {};
  const aliases = {
    first_name: ['first', 'firstname', 'first_name', 'givenname', 'given_name'],
    middle_name: ['middle', 'middlename', 'middle_name'],
    last_name: ['last', 'lastname', 'last_name', 'surname', 'family'],
    name: ['name', 'full_name', 'fullname'],
    email: ['email', 'email_address', 'emailaddress', 'e-mail'],
    position: ['position', 'role', 'post'],
    datetime: ['datetime', 'date_time', 'date', 'time', 'scheduled_datetime'],
    venue: ['venue', 'location', 'room']
  };

  headerCols.forEach((h, idx) => {
    const n = normalizeHeaderName(h);
    for (const canon in aliases) {
      if (aliases[canon].includes(n)) {
        if (!(canon in map)) map[canon] = idx;
      }
    }
    // also allow exact matches where header has the canonical name
    if (!(n in map)) {
      if (Object.keys(aliases).includes(n)) map[n] = idx;
    }
  });

  return map;
}

function importCSV(input) {
  try {
    const file = input.files ? input.files[0] : (input instanceof HTMLInputElement ? input.files[0] : null);
    if (!file) {
      console.error('No file selected for import');
      return;
    }
    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const raw = String(e.target.result || '');
        const text = raw.replace(/\r\n/g, '\n').replace(/\r/g, '\n');
        const lines = text.split('\n').filter(l => l.trim().length > 0);
        if (lines.length === 0) { showToast('CSV empty', 'warn'); return; }
        // check header row heuristically
        const headerCols = parseCSVLine(lines[0]);
        const headerMap = mapHeaderIndices(headerCols);
        const hasHeader = ('email' in headerMap) || ('name' in headerMap) || ('first_name' in headerMap);

        const startIndex = hasHeader ? 1 : 0;
        console.log('CSV import lines', lines.length, 'hasHeader', hasHeader, 'headerMap', headerMap);

        let skipped = 0;
        for (let i = startIndex; i < lines.length; i++) {
          const cols = parseCSVLine(lines[i]);
          if (!cols || cols.length === 0) { skipped++; continue; }

          const get = (key, fallbackIdx) => {
            if (key in headerMap) return cols[headerMap[key]] || '';
            if (typeof fallbackIdx === 'number') return cols[fallbackIdx] || '';
            return '';
          };

          const first = (get('first_name') || '').trim();
          const middle = (get('middle_name') || '').trim();
          const last = (get('last_name') || '').trim();
          let name = (get('name') || '').trim();

          // if name empty but parts present, combine
          if (!name && (first || middle || last)) {
            name = ((first || '') + (middle ? ' ' + middle : '') + (last ? ' ' + last : '')).trim();
          }

          // if no separate parts but name present, attempt split
          if (!first && !last && name) {
            const parts = name.split(/\s+/).filter(Boolean);
            if (parts.length === 1) { rows.push; /* nothing */ }
            else if (parts.length === 2) { /* will set below after constructing object */ }
          }

          // fallback positional mapping if no header and columns are in expected order
          let fallbackIndex = 0;
          const cand = {
            first_name: first || '',
            middle_name: middle || '',
            last_name: last || '',
            name: name || '',
            email: (get('email', 1) || '').trim(),
            position: (get('position', 2) || '').trim(),
            datetime: (get('datetime', 3) || '').trim(),
            venue: (get('venue', 4) || '').trim(),
            _raw: {}
          };

          // If name empty but CSV had a single big name at column 0, use that
          if (!cand.name) {
            cand.name = (cols[0] || '').trim();
            // try split into parts
            const parts = cand.name.split(/\s+/).filter(Boolean);
            if (parts.length === 1) { cand.first_name = parts[0]; }
            else if (parts.length === 2) { cand.first_name = parts[0]; cand.last_name = parts[1]; }
            else if (parts.length > 2) { cand.first_name = parts[0]; cand.last_name = parts[parts.length - 1]; cand.middle_name = parts.slice(1, -1).join(' '); }
          } else {
            // ensure parts set if missing
            if (!cand.first_name || !cand.last_name) {
              const parts = cand.name.split(/\s+/).filter(Boolean);
              if (parts.length === 1) cand.first_name = cand.first_name || parts[0];
              else if (parts.length === 2) { cand.first_name = cand.first_name || parts[0]; cand.last_name = cand.last_name || parts[1]; }
              else if (parts.length > 2) {
                cand.first_name = cand.first_name || parts[0];
                cand.last_name = cand.last_name || parts[parts.length - 1];
                cand.middle_name = cand.middle_name || parts.slice(1, -1).join(' ');
              }
            }
          }

          // Populate raw columns map for debugging/custom grouping
          headerCols.forEach((h, idx) => { cand._raw[normalizeHeaderName(h) || `col_${idx}`] = cols[idx] || ''; });
          // Also store any unnamed columns by index
          cols.forEach((c, idx) => { if (!headerCols[idx]) cand._raw[`col_${idx}`] = c; });

          // If email not found, try common positions
          if (!cand.email) {
            // try 1st or 2nd column heuristically
            if ((cols[1] || '').includes('@')) cand.email = (cols[1] || '').trim();
            else if ((cols[2] || '').includes('@')) cand.email = (cols[2] || '').trim();
          }

          // push row object
          const rowData = {
            first_name: cand.first_name,
            middle_name: cand.middle_name,
            last_name: cand.last_name,
            name: cand.name,
            email: cand.email,
            position: cand.position,
            datetime: cand.datetime,
            venue: cand.venue,
            _raw: cand._raw
          };
          addRow(rowData); // addRow will render
        }

        showToast(`Imported ${rows.length} aspirant(s)`, 'success');
        console.log('CSV import finished, total rows', rows.length);
        // optionally auto-generate schedule
        const autoAssign = document.getElementById('auto-assign');
        if (autoAssign && autoAssign.checked) {
          console.log('Auto assign enabled — generating schedule now');
          generateSchedule();
        }
      } catch (err) {
        console.error('Error parsing CSV', err);
        showToast('Failed to import CSV', 'error');
      }
    };
    reader.onerror = (err) => {
      console.error('FileReader error', err);
      showToast('Failed to read CSV', 'error');
    };
    reader.readAsText(file, 'UTF-8');
    if (input && input.files) input.value = '';
  } catch (err) {
    console.error('importCSV top-level error', err);
    showToast('Failed to import CSV', 'error');
  }
}

