/* SCHEDULING ALGORITHM */
function generateSchedule() {
  try {
    if (rows.length === 0) { showToast('No aspirants to schedule', 'warn'); return; }
    const startVal = document.getElementById('schedule-start').value;
    if (!startVal) { showToast('Set a start date & time first', 'error'); return; }
    let cursor = new Date(startVal);
    if (isNaN(cursor.getTime())) { showToast('Invalid start date/time', 'error'); return; }

    const slotMinutes = Math.max(1, parseInt(document.getElementById('slot-duration').value || '10', 10));
    const breakMinutes = Math.max(0, parseInt(document.getElementById('slot-break').value || '0', 10));
    const parallel = Math.max(1, parseInt(document.getElementById('parallel-slots').value || '1', 10));
    const groupBy = (document.getElementById('group-by').value || 'none');
    const customCol = (document.getElementById('group-column').value || '').trim();

    // Build ordering/grouping
    let list = rows.slice(); // shallow copy
    if (groupBy === 'position') {
      list.sort((a,b)=> (a.position||'').localeCompare(b.position||'') || (a.name||'').localeCompare(b.name||''));
    } else if (groupBy === 'custom' && customCol) {
      list.sort((a,b)=>{
        const av = (a._raw && a._raw[normalizeHeaderName(customCol)]) || '';
        const bv = (b._raw && b._raw[normalizeHeaderName(customCol)]) || '';
        return av.localeCompare(bv) || (a.name||'').localeCompare(b.name||'');
      });
    } else {
      list.sort((a,b)=> (a.name||'').localeCompare(b.name||''));
    }

    // Assign times: parallel slots means same datetime assigned to 'parallel' rows then increment cursor
    let idx = 0;
    while (idx < list.length) {
      for (let p = 0; p < parallel && idx < list.length; p++, idx++) {
        const r = list[idx];
        // format to YYYY-MM-DDTHH:MM for datetime-local inputs
        const dtStr = toLocalInputDatetime(cursor);
        r.datetime = dtStr;
      }
      // advance cursor
      cursor = new Date(cursor.getTime() + (slotMinutes + breakMinutes) * 60 * 1000);
    }

    // After assigning to sorted list, copy back into rows by id
    list.forEach(l => {
      const r = rows.find(x => x.id === l.id);
      if (r) r.datetime = l.datetime;
    });

    renderRows();
    showToast('Schedule generated', 'success');
    console.log('Generated schedule', { slotMinutes, breakMinutes, parallel });
  } catch (err) {
    console.error('generateSchedule error', err);
    showToast('Failed to generate schedule', 'error');
  }
}

function toLocalInputDatetime(d) {
  // returns "YYYY-MM-DDTHH:MM"
  const pad = (n) => String(n).padStart(2, '0');
  const year = d.getFullYear();
  const month = pad(d.getMonth() + 1);
  const date = pad(d.getDate());
  const hours = pad(d.getHours());
  const minutes = pad(d.getMinutes());
  return `${year}-${month}-${date}T${hours}:${minutes}`;
}

/* EMAIL BUILDING & SENDING */
