    .replace(/\{\{first_name\}\}/g, r.first_name || '')
    .replace(/\{\{middle_name\}\}/g, r.middle_name || '')
    .replace(/\{\{last_name\}\}/g, r.last_name || '')
    .replace(/\{\{name\}\}/g, r.name || '')
    .replace(/\{\{position\}\}/g, r.position || '')
    .replace(/\{\{date\}\}/g, dateStr)
    .replace(/\{\{time\}\}/g, timeStr)
