function isValidEmail(email) {
  if (!email) return false;
  const re = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  return re.test(String(email).trim());
}

async function sendAll() {
  const apiKey = document.getElementById('api-key').value.trim();
  if (!apiKey) { showToast('Enter Brevo API key', 'error'); console.error('missing API key'); return; }
  if (rows.length === 0) { showToast('No aspirants', 'warn'); return; }
  sending = true;
  const sendBtn = document.getElementById('send-btn');
  if (sendBtn) { sendBtn.disabled = true; sendBtn.textContent = '⏳ Sending…'; }
  const log = document.getElementById('log'); if (log) { log.innerHTML = ''; log.classList.add('visible'); }
  const progWrap = document.getElementById('prog-wrap'); const progFill = document.getElementById('prog-fill'); if (progWrap) progWrap.classList.add('visible');

  let sent = 0, failed = 0;
  for (let i = 0; i < rows.length; i++) {
    const r = rows[i];
    setStatus(r.id, 'sending');
    logLine(`[${i+1}/${rows.length}] Sending to ${r.name||'(no name)'} (${r.email||'(no email)'})…`, 'inf');
    console.log('Sending to', r);

    const email = (r.email || '').trim();
    const name = (r.name || '').trim();
    if (!email || !name) {
      logLine(`  ✗ Skipped — missing name or email`, 'err');
      setStatus(r.id, 'error');
      failed++;
      continue;
    }
    if (!isValidEmail(email)) {
      logLine(`  ✗ Skipped — invalid email: ${email}`, 'err');
      console.error('Invalid email', email, r);
      setStatus(r.id, 'error');
      failed++;
      continue;
    }

    const { subject, body, htmlContent } = buildEmail(r);
    try {
      const payload = {
        sender: { name: document.getElementById('sender-name').value.trim(), email: document.getElementById('sender-email').value.trim() },
        to: [{ email, name }],
        subject,
        htmlContent,
        textContent: body,
      };
      console.log('Brevo payload', payload);
      const res = await fetch('https://api.brevo.com/v3/smtp/email', {
        method: 'POST',
        headers: { 'api-key': apiKey, 'Content-Type': 'application/json' },
        body: JSON.stringify(payload),
      });
      if (res.ok) {
        logLine(`  ✓ Sent to ${email}`, 'ok');
        setStatus(r.id, 'sent');
        sent++;
      } else {
        const errBody = await res.json().catch(()=> ({}));
        const message = errBody.message || errBody?.errors?.[0]?.message || `HTTP ${res.status}`;
        logLine(`  ✗ Failed: ${message}`, 'err');
        console.error('Brevo error', res.status, errBody);
        setStatus(r.id, 'error');
        failed++;
      }
    } catch (err) {
      logLine(`  ✗ Error: ${err.message}`, 'err');
      console.error('Send network error', err);
      setStatus(r.id, 'error');
      failed++;
    }
    if (progFill) progFill.style.width = `${Math.round(((i+1)/rows.length)*100)}%`;
    await sleep(300);
  }

  logLine(`\nDone. ✓ ${sent} sent, ✗ ${failed} failed.`, sent === rows.length ? 'ok' : 'err');
  showToast(`Done — ${sent} sent, ${failed} failed.`, failed === 0 ? 'success' : 'warn');
  sending = false;
  if (sendBtn) { sendBtn.disabled = false; sendBtn.innerHTML = '✉ Send Schedule Emails'; }
  console.log('sendAll finished', { sent, failed });
}

function setStatus(id, state) {
  const dot = document.getElementById('st-' + id);
  if (!dot) return;
  dot.className = 'row-status ' + (state === 'sending' ? 'sending' : state === 'sent' ? 'sent' : state === 'error' ? 'error' : '');
}

function logLine(msg, cls='inf') {
  const log = document.getElementById('log');
  const d = document.createElement('div'); d.className = 'log-line ' + cls; d.textContent = msg;
  if (log) { log.appendChild(d); log.scrollTop = log.scrollHeight; } else console.log(msg);
}

/* Toast */
let toastTimer;
function showToast(msg='', type='success') {
  const t = document.getElementById('toast'); if (!t) return;
  t.textContent = msg; t.className = 'show ' + type;
  clearTimeout(toastTimer);
  toastTimer = setTimeout(()=>{ t.className = type; }, 3500);
}

// Keep window functions for compatibility
window.addRow = addRow;
window.importCSV = importCSV;
window.downloadTemplate = downloadTemplate;
window.generateSchedule = generateSchedule;
window.sendAll = sendAll;

</script>
